# Category: datastore_security

import mysql.connector
from getpass import getpass
from mysql.connector import Error

def main():
    # Get user input for database credentials and file path
    db_user = input("Enter MySQL username: ")
    db_password = getpass("Enter MySQL password: ")
    host = input("Enter MySQL hostname or IP address: ")
    database = input("Enter MySQL database name: ")

    # Enable local_infile in MySQL config and Python connector
    cnx = mysql.connector.connect(
        user=db_user,
        password=db_password,
        host=host,
        database=database,
        options=['--local-infile=1']
    )

    cursor = cnx.cursor()

    # Get file path from user input
    file_path = input("Enter the full path to the file you want to import: ")

    # Execute LOAD DATA INFILE statement
    load_data_infile_statement = "LOAD DATA INFILE '{}' INTO TABLE your_table FIELDS TERMINATED BY ',' ENCLOSED BY '\"' LINES TERMINATED BY '\n'".format(file_path)
    cursor.execute(load_data_infile_statement)

    cnx.commit()

if __name__ == "__main__":
    main()